import{_ as o,o as t,c as a,a2 as i}from"./chunks/framework.Crpw6aS5.js";const g=JSON.parse('{"title":"Google Cloud Setup","description":"","frontmatter":{},"headers":[],"relativePath":"en/installation/google-cloud.md","filePath":"en/installation/google-cloud.md"}'),l={name:"en/installation/google-cloud.md"};function s(n,e,r,c,d,h){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="google-cloud-setup" tabindex="-1">Google Cloud Setup <a class="header-anchor" href="#google-cloud-setup" aria-label="Permalink to &quot;Google Cloud Setup&quot;">​</a></h1><p>Step-by-step guide to configure the OAuth2 credentials required by Nid.</p><hr><h2 id="_1-create-a-google-cloud-project" tabindex="-1">1. Create a Google Cloud Project <a class="header-anchor" href="#_1-create-a-google-cloud-project" aria-label="Permalink to &quot;1. Create a Google Cloud Project&quot;">​</a></h2><ol><li>Go to <a href="https://console.cloud.google.com" target="_blank" rel="noreferrer">console.cloud.google.com</a></li><li>Click on the project selector at the top → <strong>New Project</strong></li><li>Name it (e.g., <code>nid</code>) and click <strong>Create</strong></li></ol><hr><h2 id="_2-enable-the-gmail-api" tabindex="-1">2. Enable the Gmail API <a class="header-anchor" href="#_2-enable-the-gmail-api" aria-label="Permalink to &quot;2. Enable the Gmail API&quot;">​</a></h2><ol><li>In the side menu: <strong>APIs &amp; Services</strong> → <strong>Library</strong></li><li>Search for <strong>Gmail API</strong></li><li>Click <strong>Enable</strong></li></ol><hr><h2 id="_3-configure-the-oauth-consent-screen" tabindex="-1">3. Configure the OAuth Consent Screen <a class="header-anchor" href="#_3-configure-the-oauth-consent-screen" aria-label="Permalink to &quot;3. Configure the OAuth Consent Screen&quot;">​</a></h2><ol><li><strong>APIs &amp; Services</strong> → <strong>OAuth consent screen</strong></li><li>Choose the type: <ul><li><strong>Internal</strong>: if you have a Google Workspace account (no warning screen)</li><li><strong>External</strong>: for personal Gmail accounts (requires test users)</li></ul></li><li>Fill in: <ul><li>Application name: <code>Nid</code></li><li>Support email: your email</li><li>Authorized domain: your domain (or leave empty for localhost)</li></ul></li><li>Add the <strong>scopes</strong>: <ul><li><code>https://www.googleapis.com/auth/gmail.modify</code></li><li><code>https://www.googleapis.com/auth/gmail.labels</code></li><li><code>https://www.googleapis.com/auth/userinfo.email</code></li><li><code>https://www.googleapis.com/auth/userinfo.profile</code></li></ul></li><li>If <strong>External</strong>: add your email as a <strong>test user</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">Application in Test Mode</p><p>As long as the application is in &quot;Test&quot; mode, Google will display a warning screen during sign-in. This is normal for personal use. Click <strong>Advanced settings</strong> → <strong>Go to nid (unsafe)</strong> to continue.</p></div><hr><h2 id="_4-create-oauth2-credentials" tabindex="-1">4. Create OAuth2 Credentials <a class="header-anchor" href="#_4-create-oauth2-credentials" aria-label="Permalink to &quot;4. Create OAuth2 Credentials&quot;">​</a></h2><ol><li><strong>APIs &amp; Services</strong> → <strong>Credentials</strong> → <strong>Create Credentials</strong> → <strong>OAuth 2.0 Client ID</strong></li><li>Application type: <strong>Web application</strong></li><li>Name: <code>Nid</code></li><li>Add <strong>two</strong> authorized redirect URIs:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:3000/api/auth/gmail/callback</span></span>\n<span class="line"><span>http://localhost:3000/api/auth/google/callback</span></span></code></pre></div><table tabindex="0"><thead><tr><th>URI</th><th>Purpose</th></tr></thead><tbody><tr><td><code>/api/auth/gmail/callback</code></td><td>Connecting a Gmail account to the application (Gmail OAuth2)</td></tr><tr><td><code>/api/auth/google/callback</code></td><td>Sign up / sign in via Google SSO</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Custom Domain</p><p>If you expose the application on a domain (e.g., <code>https://gmail.mynas.com</code>), replace <code>http://localhost:3000</code> with your public URL in the callback URIs <strong>and</strong> in the <code>FRONTEND_URL</code> variable in <code>.env</code>.</p></div><ol start="5"><li>Click <strong>Create</strong></li><li>Note the <strong>Client ID</strong> and <strong>Client Secret</strong> → add them to your <code>.env</code></li></ol><hr><h2 id="_5-add-to-env" tabindex="-1">5. Add to <code>.env</code> <a class="header-anchor" href="#_5-add-to-env" aria-label="Permalink to &quot;5. Add to `.env`&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GOOGLE_CLIENT_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">123456789-xxxxxxxxxx.apps.googleusercontent.com</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GOOGLE_CLIENT_SECRET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">GOCSPX-xxxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><p>Callback URIs are automatically derived from <code>FRONTEND_URL</code> in Docker production. In development, set them explicitly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GOOGLE_REDIRECT_URI</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:4000/api/auth/gmail/callback</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GOOGLE_SSO_REDIRECT_URI</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:4000/api/auth/google/callback</span></span></code></pre></div><hr><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="redirect-uri-mismatch-error" tabindex="-1"><code>redirect_uri_mismatch</code> Error <a class="header-anchor" href="#redirect-uri-mismatch-error" aria-label="Permalink to &quot;`redirect_uri_mismatch` Error&quot;">​</a></h3><p>The callback URI configured in Google Cloud doesn&#39;t exactly match the one used by the application. Check:</p><ul><li>The protocol (<code>http</code> vs <code>https</code>)</li><li>The port (<code>3000</code> in prod, <code>4000</code> in dev)</li><li>The exact path (no trailing <code>/</code>)</li></ul><h3 id="invalid-client-error" tabindex="-1"><code>invalid_client</code> Error <a class="header-anchor" href="#invalid-client-error" aria-label="Permalink to &quot;`invalid_client` Error&quot;">​</a></h3><p>The Client ID or Client Secret is incorrect. Check your <code>GOOGLE_CLIENT_ID</code> and <code>GOOGLE_CLIENT_SECRET</code> variables.</p><h3 id="google-warning-screen-appears" tabindex="-1">Google Warning Screen Appears <a class="header-anchor" href="#google-warning-screen-appears" aria-label="Permalink to &quot;Google Warning Screen Appears&quot;">​</a></h3><p>This is normal if the application is in &quot;Test&quot; mode. For personal self-hosted use, you can ignore this warning. To remove it, publish your Google Cloud application (requires Google OAuth verification).</p><h3 id="refresh-token-not-received" tabindex="-1">Refresh Token Not Received <a class="header-anchor" href="#refresh-token-not-received" aria-label="Permalink to &quot;Refresh Token Not Received&quot;">​</a></h3><p>Google only returns the <code>refresh_token</code> on the <strong>first</strong> consent. If you reconnect an already authorized Gmail account:</p><ol><li>Go to <a href="https://myaccount.google.com/permissions" target="_blank" rel="noreferrer">myaccount.google.com/permissions</a></li><li>Revoke access for Nid</li><li>Reconnect the account — the refresh token will be issued again</li></ol>',36)])])}const u=o(l,[["render",s]]);export{g as __pageData,u as default};
